"use client";

/**
 * KanbanBoard Component
 *
 * A drag-and-drop board for task management (Trello/Linear style).
 * Optimized for Product Mode with efficient task visualization.
 *
 * @example
 * ```tsx
 * <KanbanBoard
 *   columns={[
 *     { id: 'todo', title: 'To Do', cards: todoCards },
 *     { id: 'done', title: 'Done', cards: doneCards }
 *   ]}
 *   onCardClick={(card) => openDetail(card)}
 * />
 * ```
 */

import { forwardRef } from "react";
import { Plus, MoreHorizontal, Clock, AlertCircle } from "lucide-react";
import type {
  KanbanBoardProps,
  KanbanCard,
  KanbanColumn,
} from "./KanbanBoard.types";
import styles from "./KanbanBoard.module.css";

// Priority indicator
const PriorityIndicator = ({
  priority,
}: {
  priority?: KanbanCard["priority"];
}) => {
  if (!priority || priority === "low") return null;

  return (
    <span className={`${styles.priority} ${styles[`priority-${priority}`]}`}>
      <AlertCircle size={12} />
    </span>
  );
};

// Card component
const KanbanCardComponent = ({
  card,
  compact,
  onClick,
  draggable,
}: {
  card: KanbanCard;
  compact: boolean;
  onClick?: () => void;
  draggable: boolean;
}) => {
  return (
    <div
      className={`${styles.card} ${compact ? styles.cardCompact : ""}`}
      onClick={onClick}
      draggable={draggable}
      role="button"
      tabIndex={0}
      onKeyDown={(e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onClick?.();
        }
      }}
    >
      {card.coverImage && !compact && (
        <div className={styles.cardCover}>
          <img src={card.coverImage} alt="" />
        </div>
      )}

      <div className={styles.cardContent}>
        {/* Labels */}
        {card.labels && card.labels.length > 0 && !compact && (
          <div className={styles.labels}>
            {card.labels.map((label) => (
              <span
                key={label.id}
                className={`${styles.label} ${styles[`label-${label.color}`]}`}
              >
                {label.text}
              </span>
            ))}
          </div>
        )}

        {/* Title */}
        <div className={styles.cardTitle}>
          <PriorityIndicator priority={card.priority} />
          <span>{card.title}</span>
        </div>

        {/* Description */}
        {card.description && !compact && (
          <p className={styles.cardDescription}>{card.description}</p>
        )}

        {/* Footer */}
        {(card.dueDate || (card.assignees && card.assignees.length > 0)) && (
          <div className={styles.cardFooter}>
            {card.dueDate && (
              <span className={styles.dueDate}>
                <Clock size={12} />
                <span>{card.dueDate}</span>
              </span>
            )}

            {card.assignees && card.assignees.length > 0 && (
              <div className={styles.assignees}>
                {card.assignees.slice(0, 3).map((assignee) => (
                  <div
                    key={assignee.id}
                    className={styles.assignee}
                    title={assignee.name}
                  >
                    {assignee.avatar ? (
                      <img src={assignee.avatar} alt={assignee.name} />
                    ) : (
                      <span>{assignee.name.charAt(0)}</span>
                    )}
                  </div>
                ))}
                {card.assignees.length > 3 && (
                  <div className={styles.assigneeMore}>
                    +{card.assignees.length - 3}
                  </div>
                )}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

// Column component
const KanbanColumnComponent = ({
  column,
  compact,
  showCardCount,
  draggable,
  onCardClick,
  onAddCard,
  onColumnMenu,
}: {
  column: KanbanColumn;
  compact: boolean;
  showCardCount: boolean;
  draggable: boolean;
  onCardClick?: (card: KanbanCard) => void;
  onAddCard?: () => void;
  onColumnMenu?: () => void;
}) => {
  const isOverLimit = column.limit && column.cards.length > column.limit;

  return (
    <div className={styles.column}>
      <div className={styles.columnHeader}>
        <div className={styles.columnTitleWrapper}>
          {column.color && column.color !== "default" && (
            <span
              className={`${styles.columnDot} ${styles[`dot-${column.color}`]}`}
            />
          )}
          <h3 className={styles.columnTitle}>{column.title}</h3>
          {showCardCount && (
            <span
              className={`${styles.columnCount} ${isOverLimit ? styles.columnCountOver : ""}`}
            >
              {column.cards.length}
              {column.limit && `/${column.limit}`}
            </span>
          )}
        </div>
        <div className={styles.columnActions}>
          {onAddCard && (
            <button
              type="button"
              className={styles.columnAction}
              onClick={onAddCard}
              aria-label="Add card"
            >
              <Plus size={16} />
            </button>
          )}
          {onColumnMenu && (
            <button
              type="button"
              className={styles.columnAction}
              onClick={onColumnMenu}
              aria-label="Column menu"
            >
              <MoreHorizontal size={16} />
            </button>
          )}
        </div>
      </div>

      <div className={styles.columnCards}>
        {column.cards.map((card) => (
          <KanbanCardComponent
            key={card.id}
            card={card}
            compact={compact}
            draggable={draggable}
            onClick={() => onCardClick?.(card)}
          />
        ))}

        {column.cards.length === 0 && (
          <div className={styles.emptyColumn}>No cards yet</div>
        )}
      </div>

      {onAddCard && (
        <button
          type="button"
          className={styles.addCardButton}
          onClick={onAddCard}
        >
          <Plus size={16} />
          <span>Add card</span>
        </button>
      )}
    </div>
  );
};

export const KanbanBoard = forwardRef<HTMLDivElement, KanbanBoardProps>(
  (
    {
      columns,
      onCardMove: _onCardMove,
      onCardClick,
      onAddCard,
      onAddColumn,
      onColumnMenu,
      compact = false,
      showCardCount = true,
      draggable = true,
      className,
      ...rest
    },
    ref,
  ) => {
    const classNames = [styles.kanbanBoard, className]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        <div className={styles.columns}>
          {columns.map((column) => (
            <KanbanColumnComponent
              key={column.id}
              column={column}
              compact={compact}
              showCardCount={showCardCount}
              draggable={draggable}
              onCardClick={(card) => onCardClick?.(card, column.id)}
              onAddCard={onAddCard ? () => onAddCard(column.id) : undefined}
              onColumnMenu={
                onColumnMenu ? () => onColumnMenu(column.id) : undefined
              }
            />
          ))}

          {onAddColumn && (
            <button
              type="button"
              className={styles.addColumnButton}
              onClick={onAddColumn}
            >
              <Plus size={20} />
              <span>Add column</span>
            </button>
          )}
        </div>
      </div>
    );
  },
);

KanbanBoard.displayName = "KanbanBoard";

/**
 * KanbanBoard Component Types
 *
 * Type definitions for the Orion KanbanBoard section component.
 * A drag-and-drop board for task management (Trello/Linear style).
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Kanban card/item
 */
export interface KanbanCard {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Card title
   */
  title: string;

  /**
   * Card description
   */
  description?: string;

  /**
   * Labels/tags
   */
  labels?: KanbanLabel[];

  /**
   * Assigned users
   */
  assignees?: KanbanAssignee[];

  /**
   * Due date
   */
  dueDate?: string;

  /**
   * Priority level
   */
  priority?: "low" | "medium" | "high" | "urgent";

  /**
   * Custom metadata
   */
  metadata?: Record<string, ReactNode>;

  /**
   * Cover image URL
   */
  coverImage?: string;
}

/**
 * Kanban label
 */
export interface KanbanLabel {
  /**
   * Label ID
   */
  id: string;

  /**
   * Label text
   */
  text: string;

  /**
   * Label color
   */
  color:
    | "red"
    | "orange"
    | "yellow"
    | "green"
    | "blue"
    | "purple"
    | "pink"
    | "gray";
}

/**
 * Kanban assignee
 */
export interface KanbanAssignee {
  /**
   * User ID
   */
  id: string;

  /**
   * User name
   */
  name: string;

  /**
   * Avatar URL
   */
  avatar?: string;
}

/**
 * Kanban column
 */
export interface KanbanColumn {
  /**
   * Column ID
   */
  id: string;

  /**
   * Column title
   */
  title: string;

  /**
   * Column color/variant
   */
  color?: "default" | "blue" | "green" | "yellow" | "red" | "purple";

  /**
   * Cards in this column
   */
  cards: KanbanCard[];

  /**
   * Max cards limit (WIP limit)
   */
  limit?: number;
}

/**
 * Drag result for move operations
 */
export interface KanbanDragResult {
  /**
   * Card that was moved
   */
  cardId: string;

  /**
   * Source column ID
   */
  sourceColumnId: string;

  /**
   * Source index
   */
  sourceIndex: number;

  /**
   * Destination column ID
   */
  destinationColumnId: string;

  /**
   * Destination index
   */
  destinationIndex: number;
}

/**
 * KanbanBoard section props
 *
 * @example
 * ```tsx
 * <KanbanBoard
 *   columns={[
 *     { id: 'todo', title: 'To Do', cards: [...] },
 *     { id: 'in-progress', title: 'In Progress', cards: [...] },
 *     { id: 'done', title: 'Done', cards: [...] }
 *   ]}
 *   onCardMove={handleCardMove}
 *   onCardClick={handleCardClick}
 * />
 * ```
 */
export interface KanbanBoardProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Board columns
   */
  columns: KanbanColumn[];

  /**
   * Card move handler
   */
  onCardMove?: (result: KanbanDragResult) => void;

  /**
   * Card click handler
   */
  onCardClick?: (card: KanbanCard, columnId: string) => void;

  /**
   * Add card handler (shows add button if provided)
   */
  onAddCard?: (columnId: string) => void;

  /**
   * Add column handler (shows add column button if provided)
   */
  onAddColumn?: () => void;

  /**
   * Column menu handler
   */
  onColumnMenu?: (columnId: string) => void;

  /**
   * Compact card display
   * @default false
   */
  compact?: boolean;

  /**
   * Show card count in column headers
   * @default true
   */
  showCardCount?: boolean;

  /**
   * Enable drag and drop (visual only - actual DnD needs external library)
   * @default true
   */
  draggable?: boolean;
}

/**
 * KanbanBoard Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Clean task board with efficient visual scanning.
 */

.kanbanBoard {
  width: 100%;
  overflow-x: auto;
  padding: var(--spacing-4);
}

.columns {
  display: flex;
  gap: var(--spacing-4);
  min-height: 400px;
}

/* ============================================================================
 * COLUMN
 * ============================================================================ */

.column {
  flex-shrink: 0;
  width: 280px;
  display: flex;
  flex-direction: column;
  background: var(--surface-subtle);
  border-radius: var(--radius-control);
  max-height: 100%;
}

.columnHeader {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: var(--spacing-3) var(--spacing-3) var(--spacing-2);
  flex-shrink: 0;
}

.columnTitleWrapper {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
}

.columnDot {
  width: 8px;
  height: 8px;
  border-radius: var(--radius-full);
  flex-shrink: 0;
}

.dot-blue {
  background: var(--color-blue-500);
}
.dot-green {
  background: var(--color-green-500);
}
.dot-yellow {
  background: var(--color-yellow-500);
}
.dot-red {
  background: var(--color-red-500);
}
.dot-purple {
  background: var(--color-purple-500);
}

.columnTitle {
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-semibold);
  color: var(--text-primary);
  margin: 0;
}

.columnCount {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  font-weight: var(--font-weight-medium);
  color: var(--text-tertiary);
  background: var(--surface-base);
  padding: var(--spacing-0-5) var(--spacing-2);
  border-radius: var(--radius-full);
}

.columnCountOver {
  background: var(--status-error-bg);
  color: var(--text-error);
}

.columnActions {
  display: flex;
  gap: var(--spacing-1);
}

.columnAction {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  background: none;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  color: var(--text-tertiary);
  transition: all var(--mode-hover-duration);
}

.columnAction:hover {
  background: var(--surface-base);
  color: var(--text-primary);
}

/* ============================================================================
 * CARDS CONTAINER
 * ============================================================================ */

.columnCards {
  flex: 1;
  overflow-y: auto;
  padding: 0 var(--spacing-3);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.emptyColumn {
  padding: var(--spacing-6);
  text-align: center;
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-tertiary);
}

/* ============================================================================
 * CARD
 * ============================================================================ */

.card {
  background: var(--surface-base);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
  overflow: hidden;
}

.card:hover {
  border-color: var(--border-moderate);
  box-shadow: var(--mode-shadow-hover);
}

.card:focus-visible {
  outline: 2px solid var(--interactive-primary);
  outline-offset: 2px;
}

.card[draggable="true"] {
  cursor: grab;
}

.card[draggable="true"]:active {
  cursor: grabbing;
}

.cardCompact .cardContent {
  padding: var(--spacing-2);
}

.cardCover {
  width: 100%;
  height: 120px;
  overflow: hidden;
}

.cardCover img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.cardContent {
  padding: var(--spacing-3);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

/* Labels */
.labels {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-1);
}

.label {
  font-family: var(--font-secondary);
  font-size: var(--font-size-10);
  font-weight: var(--font-weight-medium);
  padding: var(--spacing-0-5) var(--spacing-1-5);
  border-radius: var(--radius-sm);
  text-transform: uppercase;
  letter-spacing: 0.02em;
}

.label-red {
  background: var(--color-red-100);
  color: var(--color-red-700);
}
.label-orange {
  background: var(--color-orange-100);
  color: var(--color-orange-700);
}
.label-yellow {
  background: var(--color-yellow-100);
  color: var(--color-yellow-700);
}
.label-green {
  background: var(--color-green-100);
  color: var(--color-green-700);
}
.label-blue {
  background: var(--color-blue-100);
  color: var(--color-blue-700);
}
.label-purple {
  background: var(--color-purple-100);
  color: var(--color-purple-700);
}
.label-pink {
  background: var(--color-pink-100);
  color: var(--color-pink-700);
}
.label-gray {
  background: var(--surface-subtle);
  color: var(--text-secondary);
}

/* Title */
.cardTitle {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-medium);
  color: var(--text-primary);
  line-height: var(--line-height-relaxed);
}

.priority {
  flex-shrink: 0;
  margin-top: 2px;
}

.priority-medium {
  color: var(--color-yellow-500);
}
.priority-high {
  color: var(--color-orange-500);
}
.priority-urgent {
  color: var(--color-red-500);
}

/* Description */
.cardDescription {
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
  color: var(--text-secondary);
  line-height: var(--line-height-relaxed);
  margin: 0;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

/* Footer */
.cardFooter {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--spacing-2);
  margin-top: var(--spacing-1);
}

.dueDate {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-11);
  color: var(--text-tertiary);
}

/* Assignees */
.assignees {
  display: flex;
  align-items: center;
  margin-left: auto;
}

.assignee {
  width: 24px;
  height: 24px;
  border-radius: var(--radius-full);
  background: var(--surface-subtle);
  border: 2px solid var(--surface-base);
  margin-left: -8px;
  display: flex;
  align-items: center;
  justify-content: center;
  overflow: hidden;
  font-family: var(--font-secondary);
  font-size: var(--font-size-10);
  font-weight: var(--font-weight-medium);
  color: var(--text-secondary);
}

.assignee:first-child {
  margin-left: 0;
}

.assignee img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.assigneeMore {
  width: 24px;
  height: 24px;
  border-radius: var(--radius-full);
  background: var(--surface-layer);
  border: 2px solid var(--surface-base);
  margin-left: -8px;
  display: flex;
  align-items: center;
  justify-content: center;
  font-family: var(--font-secondary);
  font-size: var(--font-size-10);
  font-weight: var(--font-weight-medium);
  color: var(--text-tertiary);
}

/* ============================================================================
 * ADD BUTTONS
 * ============================================================================ */

.addCardButton {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-1);
  width: calc(100% - var(--spacing-6));
  margin: var(--spacing-2) var(--spacing-3) var(--spacing-3);
  padding: var(--spacing-2);
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  font-weight: var(--font-weight-medium);
  color: var(--text-tertiary);
  background: none;
  border: 1px dashed var(--border-subtle);
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.addCardButton:hover {
  color: var(--text-primary);
  border-color: var(--border-moderate);
  background: var(--surface-base);
}

.addColumnButton {
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--spacing-2);
  width: 280px;
  min-height: 120px;
  padding: var(--spacing-4);
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  font-weight: var(--font-weight-medium);
  color: var(--text-tertiary);
  background: var(--surface-subtle);
  border: 2px dashed var(--border-subtle);
  border-radius: var(--radius-control);
  cursor: pointer;
  transition: all var(--mode-hover-duration);
}

.addColumnButton:hover {
  color: var(--text-primary);
  border-color: var(--border-moderate);
  background: var(--surface-layer);
}

/* ============================================================================
 * RESPONSIVE
 * ============================================================================ */

@media (max-width: 768px) {
  .column {
    width: 260px;
  }

  .kanbanBoard {
    padding: var(--spacing-2);
  }

  .columns {
    gap: var(--spacing-3);
  }
}

export { KanbanBoard } from "./KanbanBoard";
export type {
  KanbanBoardProps,
  KanbanColumn,
  KanbanCard,
  KanbanLabel,
  KanbanAssignee,
  KanbanDragResult,
} from "./KanbanBoard.types";
